const AgentSDR = () => {
  const [leads, setLeads] = React.useState([
    { id: 1, name: 'Acme Inc', contact: 'Jane Doe', score: 85, status: 'qualified', lastTouch: '2d ago' },
    { id: 2, name: 'BetaCorp', contact: 'John Smith', score: 62, status: 'contacted', lastTouch: '5d ago' },
    { id: 3, name: 'Gamma LLC', contact: 'Alice Lee', score: 45, status: 'new', lastTouch: '-' }
  ]);
  const [form, setForm] = React.useState({ name: '', contact: '', score: '', status: 'new' });
  const [filter, setFilter] = React.useState('all');

  const addLead = () => {
    if (!form.name || !form.contact) return;
    setLeads([{ id: Date.now(), name: form.name, contact: form.contact, score: Number(form.score) || 0, status: form.status, lastTouch: 'Just now' }, ...leads]);
    setForm({ name: '', contact: '', score: '', status: 'new' });
  };

  const statusColor = (s) => ({ new: '#6b7280', contacted: '#2563eb', qualified: '#16a34a', lost: '#dc2626' }[s] || '#6b7280');
  const scoreColor = (s) => s >= 80 ? '#16a34a' : s >= 50 ? '#ca8a04' : '#dc2626';

  const filtered = filter === 'all' ? leads : leads.filter(l => l.status === filter);

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '16px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Sales Development Rep'),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' } },
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px' } },
        React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', marginBottom: '4px', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Qualify Lead'),
        React.createElement('input', { value: form.name, onChange: e => setForm({ ...form, name: e.target.value }), placeholder: 'Company Name', style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } }),
        React.createElement('input', { value: form.contact, onChange: e => setForm({ ...form, contact: e.target.value }), placeholder: 'Contact Name', style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } }),
        React.createElement('input', { type: 'number', value: form.score, onChange: e => setForm({ ...form, score: e.target.value }), placeholder: 'Qualification Score (0-100)', style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } }),
        React.createElement('select', { value: form.status, onChange: e => setForm({ ...form, status: e.target.value }), style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } },
          React.createElement('option', { value: 'new' }, 'New'),
          React.createElement('option', { value: 'contacted' }, 'Contacted'),
          React.createElement('option', { value: 'qualified' }, 'Qualified'),
          React.createElement('option', { value: 'lost' }, 'Lost')
        ),
        React.createElement('button', { onClick: addLead, style: { fontSize: '12px', padding: '8px', borderRadius: '4px', border: 'none', background: '#2563eb', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Add Lead')
      ),
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px' } },
        React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
          React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Outreach Tracker'),
          React.createElement('select', { value: filter, onChange: e => setFilter(e.target.value), style: { fontSize: '11px', padding: '4px', borderRadius: '4px', border: '1px solid #d1d5db' } },
            React.createElement('option', { value: 'all' }, 'All'),
            React.createElement('option', { value: 'new' }, 'New'),
            React.createElement('option', { value: 'contacted' }, 'Contacted'),
            React.createElement('option', { value: 'qualified' }, 'Qualified'),
            React.createElement('option', { value: 'lost' }, 'Lost')
          )
        ),
        React.createElement('div', { style: { display: 'flex', flexDirection: 'column', gap: '6px', overflow: 'auto' } },
          filtered.map(l => React.createElement('div', { key: l.id, style: { background: '#fff', borderRadius: '6px', padding: '10px', border: '1px solid #e5e7eb' } },
            React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' } },
              React.createElement('span', { style: { fontWeight: 600, fontSize: '13px', color: '#111827' } }, l.name),
              React.createElement('span', { style: { fontSize: '11px', fontWeight: 600, color: statusColor(l.status), textTransform: 'uppercase' } }, l.status)
            ),
            React.createElement('div', { style: { fontSize: '12px', color: '#374151', marginBottom: '4px' } }, l.contact),
            React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
              React.createElement('span', { style: { fontSize: '11px', color: scoreColor(l.score), fontWeight: 700 } }, 'Score: ', l.score),
              React.createElement('span', { style: { fontSize: '11px', color: '#9ca3af' } }, l.lastTouch)
            )
          ))
        )
      )
    )
  );
};
render(<AgentSDR/>);
